import{_ as i,c as t,o as r,ag as a}from"./chunks/framework.091VdYs-.js";const c=JSON.parse('{"title":"daily-pi-poetry","description":"","frontmatter":{"aside":true},"headers":[],"relativePath":"projekte/daily-pi-poetry.md","filePath":"projekte/daily-pi-poetry.md"}'),n={name:"projekte/daily-pi-poetry.md"};function s(l,e,o,d,h,p){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="daily-pi-poetry" tabindex="-1">daily-pi-poetry <a class="header-anchor" href="#daily-pi-poetry" aria-label="Permalink to &quot;daily-pi-poetry&quot;">​</a></h1><p><strong>Raspberry Pi · Lokales Sprachmodell · <a href="https://github.com/dev-arts-de/daily-pi-poetry" target="_blank" rel="noreferrer">GitHub</a></strong></p><p>daily-pi-poetry ist ein kleines Experiment: Ein lokales Sprachmodell, das auf dem Raspberry Pi läuft und jeden Tag automatisch ein kurzes Gedicht generiert – ohne Cloud, ohne API-Kosten, ohne externe Abhängigkeit.</p><h2 id="die-idee" tabindex="-1">Die Idee <a class="header-anchor" href="#die-idee" aria-label="Permalink to &quot;Die Idee&quot;">​</a></h2><p>Der Raspberry Pi unter meinem Schreibtisch läuft ohnehin. Neben DailyDev, das mir täglich Lernbeiträge liefert, wollte ich testen, wie weit ein lokales Sprachmodell auf so einem kleinen Gerät sinnvoll einsetzbar ist. Keine groß angelegte KI-Infrastruktur, keine GPU – einfach ein sparsamer ARM-Prozessor, ein quantisiertes Modell und eine Frage: Was kommt dabei heraus?</p><p>Die Antwort: ein tägliches Gedicht, generiert vollständig lokal, direkt auf dem Gerät. Kein Serveraufruf, kein Internetzugang zur Laufzeit, keine Abhängigkeit von einem Dienst der morgen vielleicht kostenpflichtig wird oder wegfällt.</p><h2 id="technische-umsetzung" tabindex="-1">Technische Umsetzung <a class="header-anchor" href="#technische-umsetzung" aria-label="Permalink to &quot;Technische Umsetzung&quot;">​</a></h2><p>Das Projekt nutzt ein quantisiertes Sprachmodell, das für eingeschränkte Hardware optimiert ist und auf dem Raspberry Pi ohne externe Ressourcen betrieben werden kann. Ein Cron-Job löst die Generierung täglich zu einem festen Zeitpunkt aus, das Ergebnis wird gespeichert und – wie bei DailyDev – als Benachrichtigung aufs Mobiltelefon geschickt.</p><p>Der Quellcode liegt öffentlich auf GitHub. Das Projekt ist bewusst klein gehalten: kein Framework-Overhead, kein kompliziertes Setup. Es sollte eine Sache gut können, und das tut es.</p><h2 id="was-es-zeigt" tabindex="-1">Was es zeigt <a class="header-anchor" href="#was-es-zeigt" aria-label="Permalink to &quot;Was es zeigt&quot;">​</a></h2><p>Das Interessante an diesem Experiment ist nicht das Gedicht selbst – es geht um die Frage, was auf einem 50-Euro-Gerät ohne Internetverbindung zur Laufzeit möglich ist. Die Antwort ist: mehr als man erwartet. Lokale Sprachmodelle sind für viele Alltagsanwendungen inzwischen brauchbar, besonders wenn die Anforderungen klar und begrenzt sind. Ein tägliches Gedicht ist ein denkbar einfacher Anwendungsfall – aber er zeigt das Prinzip.</p><hr><p><a href="https://github.com/dev-arts-de/daily-pi-poetry" class="cv-download-link" target="_blank" rel="noreferrer">GitHub – daily-pi-poetry</a></p>',13)])])}const g=i(n,[["render",s]]);export{c as __pageData,g as default};
